body.script:

function fit() {
  var vw = window.innerWidth;
  var vh = window.innerHeight;
  function calibrate(el, opts) {
    if (!el) return;
    if (opts.fontSize != null) {
      el.style.fontSize = opts.fontSize;
    }
    if (opts.lineHeight) el.style.lineHeight = opts.lineHeight;
    if (opts.letterSpacing) el.style.letterSpacing = opts.letterSpacing;

    // measure at three stretch points: 25%, 100%, 151%
    el.style.fontStretch = '25%';
    var w25 = el.offsetWidth;
    el.style.fontStretch = '100%';
    var w100 = el.offsetWidth;
    el.style.fontStretch = '151%';
    var w151 = el.offsetWidth;

    // piecewise linear model
    var m1 = (w100 - w25) / 75;
    var c1 = w25 - m1 * 25;
    var m2 = (w151 - w100) / 51;
    var c2 = w100 - m2 * 100;

    var targetW = vw * opts.targetWidthVw / 100;
    var s;
    if (targetW <= w100) {
      s = Math.round((targetW - c1) / m1);
    } else {
      s = Math.round((targetW - c2) / m2);
    }
    s = Math.max(25, Math.min(151, s));
    el.style.fontStretch = s + '%';
  }

  calibrate(document.querySelector('#s2 > h2'), {
    fontSize: (100 / 0.8 / 100 * vh) + 'px',
    targetWidthVw: 50,
    lineHeight: 0.8,
    letterSpacing: '-0.02em'
  });
  calibrate(document.querySelector('#s5 > h2'), {
    fontSize: (75 / 0.8 / 100 * vh) + 'px',
    targetWidthVw: 100,
    lineHeight: 0.8,
    letterSpacing: '-0.02em'
  });
  calibrate(document.querySelector('#s1 > h1'), {
    targetWidthVw: 99,
    lineHeight: 1,
    letterSpacing: '-0.05em'
  });
}
window.addEventListener('resize', fit);
fit();
